                    if (self.hcErrorCount > 0) {
                        setValueInStorage(healthCheckCounterEnum.errorCount, self.hcErrorCount);
                    }
                    if (self.hcWarningCount > 0) {
                        setValueInStorage(healthCheckCounterEnum.warningCount, self.hcWarningCount);
                    }
